function I(s){const i=s.taxonomy.classes.filter(e=>e.includeInExport!==!1),r=new Set(i.map(e=>e.id)),t=i.map(e=>({id:e.index+1,name:e.name,supercategory:"none"})),h={images:[{id:1,width:s.imageWidth,height:s.imageHeight,file_name:s.imageName}],annotations:s.objects.filter(e=>r.has(e.classId)).map((e,c)=>{const x=s.taxonomy.classes.find(l=>l.id===e.classId);let n=[],d=[],p=0;if(e.type==="bbox")n=e.coordinates,p=n[2]*n[3];else if(e.type==="polygon"){d=[e.coordinates];let l=1/0,m=1/0,y=-1/0,a=-1/0;for(let o=0;o<e.coordinates.length;o+=2)l=Math.min(l,e.coordinates[o]),m=Math.min(m,e.coordinates[o+1]),y=Math.max(y,e.coordinates[o]),a=Math.max(a,e.coordinates[o+1]);n=[l,m,y-l,a-m],p=n[2]*n[3]}return{id:c+1,image_id:1,category_id:(x?.index??0)+1,segmentation:d,area:p,bbox:n,iscrowd:0}}),categories:t};return JSON.stringify(h,null,2)}function w(s){const i=s.taxonomy.classes.filter(t=>t.includeInExport!==!1),r=new Set(i.map(t=>t.id));return s.objects.filter(t=>r.has(t.classId)).map(t=>{const e=s.taxonomy.classes.find(a=>a.id===t.classId)?.index??0;let c=0,x=0,n=0,d=0;if(t.type==="bbox")[c,x,n,d]=t.coordinates;else if(t.type==="polygon"){let a=1/0,o=1/0,g=-1/0,u=-1/0;for(let f=0;f<t.coordinates.length;f+=2)a=Math.min(a,t.coordinates[f]),o=Math.min(o,t.coordinates[f+1]),g=Math.max(g,t.coordinates[f]),u=Math.max(u,t.coordinates[f+1]);c=a,x=o,n=g-a,d=u-o}const p=(c+n/2)/s.imageWidth,l=(x+d/2)/s.imageHeight,m=n/s.imageWidth,y=d/s.imageHeight;return`${e} ${p.toFixed(6)} ${l.toFixed(6)} ${m.toFixed(6)} ${y.toFixed(6)}`}).join(`
`)}function C(s){const i=s.taxonomy.classes.filter(e=>e.includeInExport),r=new Set(i.map(e=>e.id)),t=new Set(s.taxonomy.predicates.filter(e=>e.includeInExport).map(e=>e.name)),h={image_id:1,objects:s.objects.filter(e=>r.has(e.classId)).map(e=>({object_id:e.id,x:e.type==="bbox"?e.coordinates[0]:0,y:e.type==="bbox"?e.coordinates[1]:0,w:e.type==="bbox"?e.coordinates[2]:0,h:e.type==="bbox"?e.coordinates[3]:0,names:[i.find(c=>c.id===e.classId)?.name||"unknown"],synsets:[]})),relationships:s.relations.filter(e=>t.has(e.relationTypeName)).map((e,c)=>({relationship_id:c+1,predicate:e.relationTypeName,subject_id:e.sourceId,object_id:e.targetId,synsets:[]}))};return JSON.stringify(h,null,2)}self.onmessage=s=>{const{data:i,format:r}=s.data;try{let t="";switch(r){case"coco":t=I(i);break;case"yolo":t=w(i);break;case"visual_genome":t=C(i);break;default:throw new Error(`Unsupported format: ${r}`)}self.postMessage({result:t,success:!0})}catch(t){self.postMessage({error:t.message,success:!1})}};
